SELECT chart_track_table.chart_id, chart_track_table.music_content_cnt, chart_track_table.chart_nm, chart_track_table.create_dtime, chart_track_table.update_dtime, chart_track_table.track_nm, chart_track_table.disp_start_dtime, chart_track_table.img_size, chart_track_table.img_url, chart_track_table.disp_sn trackSn, chart_track_table.bf_disp_sn trackBfSn, chart_track_table.svc_streaming_yn, chart_track_table.svc_drm_yn, chart_track_table.free_yn, CONVERT (chart_track_table.bf_disp_sn , SIGNED ) - CONVERT (chart_track_table.disp_sn , SIGNED )AS rankBadge, CASE WHEN chart_track_table.bf_disp_sn = 0 THEN 'Y' ELSE 'N' END AS newYn, c.track_id, a.album_id, d.artist_id, d.artist_nm, b.album_img_size size, b.album_img_url url, e.artist_id reqArtistId, e.artist_nm reqArtistNm FROM ( SELECT chart_img_table.chart_id, chart_img_table.music_content_cnt, chart_img_table.chart_nm, chart_img_table.create_dtime, chart_img_table.update_dtime, chart_img_table.disp_start_dtime, chart_img_table.img_size, chart_img_table.img_url, b.music_content_id, b.disp_sn, b.bf_disp_sn, c.track_id, c.track_nm, c.album_id, c.reprsnt_artist_id, c.svc_streaming_yn, c.svc_drm_yn, c.free_yn FROM ( SELECT a.chart_id, a.music_content_cnt, b.prefer_disp_nm chart_nm, b.prefer_disp_nm chart_disp_nm, a.create_dtime, a.update_dtime, a.disp_start_dtime, c.img_size, c.img_url FROM tb_chart a LEFT OUTER JOIN tb_prefer_disp b ON a.chart_id = b.disp_id AND b.disp_type = 'CHART' AND b.disp_props_type = #{chartPanelType.dispPropsType} LEFT OUTER JOIN tb_img_mang c ON b.prefer_disp_id = c.img_content_id AND c.img_content_type = 'DISP' AND c.dfk_type = 'EVERY' AND c.img_disp_type = 'MAIN_TOP' AND c.os_type = #{osType} WHERE a.svc_content_type = #{chartPanelType.svcContentType} AND a.chart_type = #{chartPanelType.chartType} AND a.music_content_type = #{chartPanelType.musicContentType}
AND a.svc_content_id =23
) chart_img_table INNER JOIN tb_chart_music_content b ON chart_img_table.chart_id = b.chart_id INNER JOIN tb_track c ON b.music_content_id = c.track_id AND c.disp_status_yn = 'Y' AND now() BETWEEN c.disp_start_dtime AND c.disp_end_dtime ORDER BY b.disp_sn LIMIT #{trackLimitSize} ) chart_track_table INNER JOIN ted_album a ON chart_track_table.album_id = a.album_id AND a.disp_status_yn = 'Y' AND now() BETWEEN a.disp_start_dtime AND a.disp_end_dtime LEFT OUTER JOIN tb_album_img b ON a.album_id = b.album_id LEFT OUTER JOIN ted_trackartist c ON chart_track_table.track_id =c.track_id AND c.rp_yn = 'Y' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN ted_artist e ON e.artist_id = chart_track_table.reprsnt_artist_id
